1	const PROCESSING_FEE = 5;
2	const DEDUCTIBLE = 100;
3	
4	const BASE_PREMIUMS: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	  rune: 25,
10	};
11	
12	const INSURANCE_VALUES: Record<string, number> = {
13	  sword: 1000,
14	  amulet: 600,
15	  staff: 800,
16	  potion: 400,
17	};
18	
19	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
20	const BLOCK_SIZE = 3;
21	const BLOCK_PREMIUM = 60;
22	const COMPONENT_PREMIUM = 25;
23	
24	const CURSE_SURCHARGE_RATE = 0.5;
25	const HIGH_ENCHANTMENT_QUOTE_THRESHOLD = 5;
26	const HIGH_ENCHANTMENT_QUOTE_SURCHARGE_RATE = 0.3;
27	
28	const LOYALTY_DISCOUNT_RATE = 0.2;
29	const LOYALTY_MIN_YEARS = 2;
30	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
31	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
32	
33	const calculateItemSurcharges = (item: any, base: number): number => {
34	  const curseSurcharge = item.cursed ? base * CURSE_SURCHARGE_RATE : 0;
35	  const enchantmentSurcharge =
36	    item.enchantment >= HIGH_ENCHANTMENT_QUOTE_THRESHOLD
37	      ? base * HIGH_ENCHANTMENT_QUOTE_SURCHARGE_RATE
38	      : 0;
39	  return curseSurcharge + enchantmentSurcharge;
40	};
41	
42	const countByType = (items: any[]): Record<string, number> =>
43	  items.reduce((counts: Record<string, number>, item) => {
44	    if (COMPONENT_TYPES.has(item.type)) {
45	      counts[item.type] = (counts[item.type] || 0) + 1;
46	    }
47	    return counts;
48	  }, {});
49	
50	const calculateComponentsCost = (items: any[]): number =>
51	  Object.values(countByType(items)).reduce(
52	    (total, count) => total + (count === BLOCK_SIZE ? BLOCK_PREMIUM : count * COMPONENT_PREMIUM),
53	    0
54	  );
55	
56	const calculatePolicyModifiers = (basePremium: number, customer: any, quoteIndex: number): number => {
57	  const loyaltyDiscount = customer.yearsWithMHPCO >= LOYALTY_MIN_YEARS
58	    ? basePremium * LOYALTY_DISCOUNT_RATE
59	    : 0;
60	  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
61	  const followUpDiscount = quoteIndex > 0
62	    ? basePremium * FOLLOW_UP_DISCOUNT_RATE
63	    : 0;
64	  return firstInsuranceSurcharge - loyaltyDiscount - followUpDiscount;
65	};
66	
67	const calculateQuotePremium = (items: any[], customer: any, quoteIndex: number): { premium: number } => {
68	  for (const item of items) {
69	    if (!BASE_PREMIUMS[item.type] && !COMPONENT_TYPES.has(item.type)) {
70	      throw new Error(`Unknown item type: ${item.type}`);
71	    }
72	  }
73	  const equipmentItems = items.filter((item) => !COMPONENT_TYPES.has(item.type));
74	
75	  const equipmentBasePremiums = equipmentItems.map((item) => BASE_PREMIUMS[item.type] || 0);
76	  const equipmentBasePremium = equipmentBasePremiums.reduce((sum, bp) => sum + bp, 0);
77	  const itemSurcharges = equipmentItems.reduce(
78	    (sum, item, i) => sum + calculateItemSurcharges(item, equipmentBasePremiums[i]),
79	    0
80	  );
81	  const componentsCost = calculateComponentsCost(items);
82	
83	  const policyBasePremium = equipmentBasePremium + componentsCost;
84	  const policyModifiers = calculatePolicyModifiers(policyBasePremium, customer, quoteIndex);
85	
86	  return { premium: Math.ceil(policyBasePremium + itemSurcharges + policyModifiers + PROCESSING_FEE) };
87	};
88	
89	const COMPONENT_INSURANCE_VALUE = 250;
90	
91	const calculateInsuranceSum = (items: any[]): number => {
92	  return items.reduce((sum, item) => {
93	    if (COMPONENT_TYPES.has(item.type)) {
94	      return sum + COMPONENT_INSURANCE_VALUE;
95	    }
96	    return sum + (INSURANCE_VALUES[item.type] || 0);
97	  }, 0);
98	};
99	
100	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
101	const HIGH_ENCHANTMENT_CLAIM_RATE = 0.5;
102	
103	const processClaim = (step: any, policies: any[]): { payout: number; remainingCap: number } => {
104	  const policy = policies[step.policy];
105	  const damageCounts: Record<string, number> = {};
106	  for (const damage of step.incident.damages) {
107	    damageCounts[damage.itemType] = (damageCounts[damage.itemType] || 0) + 1;
108	  }
109	  for (const [itemType, count] of Object.entries(damageCounts)) {
110	    const policyCount = policy.items.filter((item: any) => item.type === itemType).length;
111	    if (count > policyCount) {
112	      throw new Error(`More damages of type ${itemType} than policy covers`);
113	    }
114	  }
115	  const totalPayout = step.incident.damages.reduce((sum: number, damage: any) => {
116	    const policyItem = policy.items.find((item: any) => item.type === damage.itemType);
117	    if (!policyItem) {
118	      throw new Error(`Item type ${damage.itemType} not in policy`);
119	    }
120	    if (damage.amount < 0) {
121	      throw new Error(`Negative damage amount: ${damage.amount}`);
122	    }
123	    const reimbursement = policyItem.enchantment >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD
124	      ? damage.amount * HIGH_ENCHANTMENT_CLAIM_RATE
125	      : damage.amount;
126	    return sum + Math.max(0, reimbursement - DEDUCTIBLE);
127	  }, 0);
128	  const cappedPayout = Math.floor(Math.min(totalPayout, policy.remainingCap));
129	  policy.remainingCap -= cappedPayout;
130	  return { payout: cappedPayout, remainingCap: policy.remainingCap };
131	};
132	
133	export const processScenario = (scenario: any): any => {
134	  const policies: any[] = [];
135	  const results = scenario.steps.map((step: any) => {
136	    if (step.op === "claim") {
137	      return processClaim(step, policies);
138	    }
139	    const result = calculateQuotePremium(step.items, scenario.customer, policies.length);
140	    const insuranceSum = calculateInsuranceSum(step.items);
141	    policies.push({
142	      items: step.items,
143	      insuranceSum,
144	      remainingCap: insuranceSum * 2,
145	    });
146	    return result;
147	  });
148	  return { results };
149	};
